import type { ToolDefinition } from "../types.js";
import { clampLimit, cursorAndLimitSchema, decodeCursor, idOnlySchema, paginate } from "./_helpers.js";
import { confirmDestructive } from "../elicit.js";
import { McpToolError } from "../errors.js";

type ListResp = { data: unknown[]; meta: { total: number; limit: number; offset: number } };

export const list_refunds: ToolDefinition = {
  name: "list_refunds",
  description:
    "List refunds for the API key's project. Most recent first. Use cursor to page.",
  inputSchema: cursorAndLimitSchema,
  annotations: { readOnlyHint: true, title: "List refunds" },
  requiredScopes: ["refunds:read"],
  async handler(args, ctx) {
    const a = args as { cursor?: string; limit?: number };
    const limit = clampLimit(a.limit);
    const { offset } = decodeCursor(a.cursor);
    const raw = await ctx.api.get<ListResp>("/v1/refunds", { query: { limit, offset } });
    return paginate(raw, limit, offset);
  },
};

export const get_refund: ToolDefinition = {
  name: "get_refund",
  description:
    "Fetch a single refund by id. Returns the refund's amount, status, reason, notes, and the underlying payment id.",
  inputSchema: idOnlySchema("refund_id", "PayBridgeNP refund id (e.g., rfd_abc123)."),
  annotations: { readOnlyHint: true, title: "Get refund" },
  requiredScopes: ["refunds:read"],
  async handler(args, ctx) {
    const { refund_id } = args as { refund_id: string };
    if (!refund_id) throw new Error("refund_id is required");
    return ctx.api.get(`/v1/refunds/${encodeURIComponent(refund_id)}`);
  },
};

const REFUND_REASONS = ["customer_request", "duplicate", "fraudulent", "other"] as const;
type RefundReason = (typeof REFUND_REASONS)[number];

export const create_refund: ToolDefinition = {
  name: "create_refund",
  description:
    "Issue a refund against a successful payment. Amount is in PAISA (e.g., 50000 = Rs 500). Pass amount to refund a partial amount; omit to refund the full payment. Always asks the user to confirm before executing.",
  inputSchema: {
    type: "object",
    properties: {
      payment_id: {
        type: "string",
        description: "PayBridgeNP payment id to refund (must be a successful payment).",
      },
      amount: {
        type: "integer",
        minimum: 1,
        description: "Refund amount in paisa (1/100 of NPR). Omit to refund the full payment amount.",
      },
      reason: {
        type: "string",
        enum: REFUND_REASONS,
        description: "Why the refund is being issued.",
      },
      notes: {
        type: "string",
        description: "Optional internal note for the merchant's records.",
      },
    },
    required: ["payment_id", "reason"],
    additionalProperties: false,
  },
  annotations: { destructiveHint: true, title: "Issue refund" },
  requiredScopes: ["refunds:write"],
  async handler(args, ctx) {
    const a = args as {
      payment_id: string;
      amount?: number;
      reason: RefundReason;
      notes?: string;
    };
    if (!a.payment_id) throw new Error("payment_id is required");
    if (!REFUND_REASONS.includes(a.reason)) {
      throw new Error(`reason must be one of: ${REFUND_REASONS.join(", ")}`);
    }

    // Hydrate the payment so the confirmation modal shows the merchant the
    // exact amount + customer being refunded — not just an opaque id.
    const payment = await ctx.api
      .get<{ id: string; amount: number; currency: string; customerEmail?: string | null; provider?: string }>(
        `/v1/payments/${encodeURIComponent(a.payment_id)}`,
      )
      .catch(() => null);

    if (!payment) {
      throw new McpToolError("not_found", `Payment ${a.payment_id} not found`, 404);
    }

    const refundAmount = a.amount ?? payment.amount;
    if (refundAmount > payment.amount) {
      throw new McpToolError(
        "invalid_request",
        `Refund amount ${refundAmount} exceeds payment amount ${payment.amount}`,
        400,
      );
    }

    const ok = await confirmDestructive(ctx.elicit, {
      message: `Issue a ${refundAmount === payment.amount ? "FULL" : "PARTIAL"} refund of ${formatPaisa(refundAmount, payment.currency)} on payment ${payment.id}?`,
      summary: {
        payment_id: payment.id,
        refund_amount: formatPaisa(refundAmount, payment.currency),
        original_amount: formatPaisa(payment.amount, payment.currency),
        customer: payment.customerEmail ?? "(unknown)",
        provider: payment.provider ?? "(unknown)",
        reason: a.reason,
      },
    });

    if (!ok) {
      throw new McpToolError("user_cancelled", "Refund cancelled by user.", 0);
    }

    return ctx.api.post("/v1/refunds", {
      body: {
        paymentId: a.payment_id,
        amount: refundAmount,
        reason: a.reason,
        notes: a.notes,
      },
    });
  },
};

function formatPaisa(amount: number, currency: string): string {
  const major = (amount / 100).toFixed(2);
  return `${currency} ${major}`;
}
