// Thin Bearer-auth fetch wrapper around apps/api. The MCP server NEVER
// forwards the MCP client's bearer/OAuth token upstream — this client
// holds the merchant's underlying PayBridgeNP API key (passed in at
// construction) and uses it for every call.
//
// Spec requirement: the MCP 2025-11-25 authorization spec forbids token
// passthrough; that's why this client takes an apiKey, not a request-time
// bearer.

import { fromUpstream, McpToolError } from "../errors.js";

const DEFAULT_BASE_URL = "https://api.paybridgenp.com";
const DEFAULT_TIMEOUT_MS = 30_000;
const DEFAULT_MAX_RETRIES = 2;
const RETRYABLE_STATUSES = new Set([500, 502, 503, 504]);

export type ApiClientConfig = {
  apiKey: string;
  baseUrl?: string;
  timeoutMs?: number;
  maxRetries?: number;
  userAgent?: string;
};

export type RequestOptions = {
  query?: Record<string, string | number | boolean | undefined | null>;
  body?: unknown;
  idempotencyKey?: string;
};

export class ApiClient {
  private readonly baseUrl: string;
  private readonly apiKey: string;
  private readonly timeoutMs: number;
  private readonly maxRetries: number;
  private readonly userAgent: string;

  constructor(cfg: ApiClientConfig) {
    if (!cfg.apiKey) {
      throw new McpToolError("unauthorized", "Missing PayBridgeNP API key", 401);
    }
    this.apiKey = cfg.apiKey;
    this.baseUrl = (cfg.baseUrl ?? process.env.PAYBRIDGE_API_BASE_URL ?? DEFAULT_BASE_URL).replace(/\/$/, "");
    this.timeoutMs = cfg.timeoutMs ?? DEFAULT_TIMEOUT_MS;
    this.maxRetries = cfg.maxRetries ?? DEFAULT_MAX_RETRIES;
    this.userAgent = cfg.userAgent ?? `PayBridgeNP-MCP/${process.env.npm_package_version ?? "0.1.0"}`;
  }

  get<T>(path: string, opts?: Pick<RequestOptions, "query">): Promise<T> {
    return this.request<T>("GET", path, opts);
  }

  post<T>(path: string, opts?: RequestOptions): Promise<T> {
    return this.request<T>("POST", path, opts);
  }

  patch<T>(path: string, opts?: RequestOptions): Promise<T> {
    return this.request<T>("PATCH", path, opts);
  }

  delete<T>(path: string, opts?: Pick<RequestOptions, "query">): Promise<T> {
    return this.request<T>("DELETE", path, opts);
  }

  private async request<T>(
    method: string,
    path: string,
    opts: RequestOptions = {},
  ): Promise<T> {
    const url = this.buildUrl(path, opts.query);
    const headers: Record<string, string> = {
      Authorization: `Bearer ${this.apiKey}`,
      "User-Agent": this.userAgent,
    };
    if (opts.body !== undefined) {
      headers["Content-Type"] = "application/json";
    }
    if (opts.idempotencyKey) {
      headers["Idempotency-Key"] = opts.idempotencyKey;
    }

    let attempt = 0;
    while (true) {
      attempt++;
      let res: Response;
      try {
        res = await fetch(url, {
          method,
          headers,
          body: opts.body !== undefined ? JSON.stringify(opts.body) : undefined,
          signal: AbortSignal.timeout(this.timeoutMs),
        });
      } catch (err) {
        if (attempt > this.maxRetries) {
          throw new McpToolError(
            "connection_error",
            `Connection error reaching ${this.baseUrl}: ${(err as Error).message}`,
            0,
          );
        }
        await sleep(backoff(attempt));
        continue;
      }

      if (res.ok) {
        if (res.status === 204) return undefined as T;
        const text = await res.text();
        return (text ? JSON.parse(text) : undefined) as T;
      }

      if (RETRYABLE_STATUSES.has(res.status) && attempt <= this.maxRetries) {
        const retryAfter = res.headers.get("Retry-After");
        const delay = retryAfter ? Number.parseInt(retryAfter, 10) * 1000 : backoff(attempt);
        await sleep(delay);
        continue;
      }

      let raw: Record<string, unknown> | null = null;
      try {
        raw = (await res.json()) as Record<string, unknown>;
      } catch {
        // upstream returned non-JSON; leave raw as null.
      }
      throw fromUpstream(res.status, raw);
    }
  }

  private buildUrl(path: string, query?: RequestOptions["query"]): string {
    const url = new URL(path.startsWith("/") ? path : `/${path}`, this.baseUrl);
    if (query) {
      for (const [k, v] of Object.entries(query)) {
        if (v !== undefined && v !== null) {
          url.searchParams.set(k, String(v));
        }
      }
    }
    return url.toString();
  }
}

function sleep(ms: number): Promise<void> {
  return new Promise((r) => setTimeout(r, ms));
}

function backoff(attempt: number): number {
  return 500 * 2 ** (attempt - 1) + Math.random() * 100;
}
