import type { ToolDefinition } from "../types.js";
import { clampLimit, cursorAndLimitSchema, decodeCursor, idOnlySchema, paginate } from "./_helpers.js";

type ListResp = { data: unknown[]; meta?: { total?: number; limit?: number; offset?: number } };

export const list_checkout_sessions: ToolDefinition = {
  name: "list_checkout_sessions",
  description:
    "List checkout sessions for the API key's project. A session represents a customer's attempt at paying via the hosted checkout page. Each session has status (pending / initiated / success / failed / expired), amount, customer, and timestamps. Use this to see in-flight or recently abandoned checkouts.",
  inputSchema: {
    type: "object",
    properties: {
      cursor: cursorAndLimitSchema.properties.cursor,
      limit: cursorAndLimitSchema.properties.limit,
      status: {
        type: "string",
        enum: ["pending", "initiated", "success", "failed", "expired"],
        description: "Optional status filter.",
      },
    },
    additionalProperties: false,
  },
  annotations: { readOnlyHint: true, title: "List checkout sessions" },
  requiredScopes: ["sessions:read"],
  async handler(args, ctx) {
    const a = args as { cursor?: string; limit?: number; status?: string };
    const limit = clampLimit(a.limit);
    const { offset } = decodeCursor(a.cursor);
    const raw = await ctx.api.get<ListResp>("/v1/sessions", {
      query: { limit, offset, status: a.status },
    });
    return paginate(raw, limit, offset);
  },
};

export const get_checkout_session: ToolDefinition = {
  name: "get_checkout_session",
  description: "Fetch a single checkout session by id.",
  inputSchema: idOnlySchema("session_id", "Checkout session id (e.g., cs_abc123)."),
  annotations: { readOnlyHint: true, title: "Get checkout session" },
  requiredScopes: ["sessions:read"],
  async handler(args, ctx) {
    const { session_id } = args as { session_id: string };
    if (!session_id) throw new Error("session_id is required");
    return ctx.api.get(`/v1/sessions/${encodeURIComponent(session_id)}`);
  },
};
