// Per-tool instrumentation. Wraps a ToolDefinition's handler with:
//   - elapsed_ms timing
//   - args_hash (sha256 of normalized args, never raw PII)
//   - fire-and-forget POST to apps/api `/v1/internal/mcp-audit` so the server
//     can write a `mcp.tool.<name>` audit row used by the admin observability
//     dashboard, auto-pause anomaly detector, and daily digest.
//
// Transports (packages/mcp stdio, future apps/api streamable HTTP) call
// dispatchTool() instead of def.handler() directly.

import { createHash } from "node:crypto";
import { McpToolError } from "./errors.js";
import { ScopeError } from "./scopes.js";
import type { ToolContext, ToolDefinition } from "./types.js";

const AUDIT_PATH = "/v1/internal/mcp-audit";
const AUDIT_TIMEOUT_MS = 4_000;

export async function dispatchTool<TArgs, TResult>(
  def: ToolDefinition<TArgs, TResult>,
  args: TArgs,
  ctx: ToolContext,
): Promise<TResult> {
  const startedAt = Date.now();
  const argsHash = hashArgs(args);
  let result: TResult;
  try {
    result = await def.handler(args, ctx);
  } catch (err) {
    void emitAudit(ctx, {
      tool: def.name,
      elapsed_ms: Date.now() - startedAt,
      result: "error",
      args_hash: argsHash,
      error_code: errorCode(err),
    });
    throw err;
  }
  void emitAudit(ctx, {
    tool: def.name,
    elapsed_ms: Date.now() - startedAt,
    result: "ok",
    args_hash: argsHash,
  });
  return result;
}

type AuditPayload = {
  tool: string;
  elapsed_ms: number;
  result: "ok" | "error";
  args_hash: string;
  error_code?: string;
};

async function emitAudit(ctx: ToolContext, payload: AuditPayload): Promise<void> {
  try {
    await ctx.api.post<unknown>(AUDIT_PATH, {
      body: payload,
    });
  } catch {
    // never throw out of instrumentation
  }
}

function hashArgs(args: unknown): string {
  const normalized = JSON.stringify(normalize(args));
  return createHash("sha256").update(normalized).digest("hex");
}

// Recursively sort object keys so {a:1,b:2} and {b:2,a:1} hash identically.
// Strings and numbers pass through unchanged. Strips undefined.
function normalize(v: unknown): unknown {
  if (v === null || v === undefined) return null;
  if (Array.isArray(v)) return v.map(normalize);
  if (typeof v === "object") {
    const sorted: Record<string, unknown> = {};
    for (const k of Object.keys(v as Record<string, unknown>).sort()) {
      const val = (v as Record<string, unknown>)[k];
      if (val !== undefined) sorted[k] = normalize(val);
    }
    return sorted;
  }
  return v;
}

function errorCode(err: unknown): string {
  if (err instanceof ScopeError) return "missing_scope";
  if (err instanceof McpToolError) return err.code;
  return "tool_error";
}
