// Internal helpers shared across tool modules.

const DEFAULT_LIMIT = 25;
const MAX_LIMIT = 100;

export type Cursor = { offset: number };

export function encodeCursor(c: Cursor): string {
  return Buffer.from(JSON.stringify(c), "utf8").toString("base64url");
}

export function decodeCursor(cursor: unknown): Cursor {
  if (cursor == null || cursor === "") return { offset: 0 };
  if (typeof cursor !== "string") {
    throw new Error("cursor must be a string");
  }
  try {
    const parsed = JSON.parse(Buffer.from(cursor, "base64url").toString("utf8")) as Cursor;
    if (typeof parsed.offset !== "number" || parsed.offset < 0) {
      throw new Error("invalid cursor");
    }
    return parsed;
  } catch {
    throw new Error("cursor is malformed");
  }
}

export function clampLimit(raw: unknown): number {
  const n = typeof raw === "number" ? raw : Number.parseInt(String(raw ?? ""), 10);
  if (!Number.isFinite(n) || n < 1) return DEFAULT_LIMIT;
  return Math.min(MAX_LIMIT, Math.floor(n));
}

// Translate the API's { data, meta: { total, limit, offset } } shape into the
// MCP-friendly { items, next_cursor, total } shape. Hides limit/offset from
// the model — agents do better with cursors than with arithmetic.
export type ListResponse<T> = {
  items: T[];
  next_cursor: string | null;
  total: number;
};

export function paginate<T>(
  raw: { data: T[]; meta?: { total?: number; limit?: number; offset?: number } },
  limit: number,
  offset: number,
): ListResponse<T> {
  const total = Number(raw.meta?.total ?? raw.data.length);
  const consumed = offset + raw.data.length;
  const next: string | null = consumed < total ? encodeCursor({ offset: consumed }) : null;
  return { items: raw.data, next_cursor: next, total };
}

// Common reusable input schemas (JSON Schema / Draft 7).
export const cursorAndLimitSchema = {
  type: "object" as const,
  properties: {
    cursor: {
      type: "string",
      description: "Opaque pagination token from a previous response. Omit on the first call.",
    },
    limit: {
      type: "integer",
      minimum: 1,
      maximum: MAX_LIMIT,
      default: DEFAULT_LIMIT,
      description: `Maximum items to return (1–${MAX_LIMIT}, default ${DEFAULT_LIMIT}).`,
    },
  },
  additionalProperties: false,
};

export function idOnlySchema(name: string, description: string) {
  return {
    type: "object" as const,
    properties: {
      [name]: { type: "string", description },
    },
    required: [name],
    additionalProperties: false,
  };
}
