// Confirmation gates for destructive write tools. Lives in mcp-core so both
// transports (stdio + remote streamable HTTP) share the same UX.
//
// MCP elicitation is a server → client request: the host shows a confirmation
// UI, returns {action: "accept"|"decline"|"cancel", content?}. We map that to
// a simple "did the user say yes?" boolean.
//
// If the host doesn't support elicitation (older clients), we fail closed
// per zzzzzzzz-mcp.md §6.3 — the caller throws an actionable error.

import { McpToolError, type ElicitFn } from "./index.js";

export type ConfirmRequest = {
  // Headline message shown to the user. Keep < 200 chars.
  message: string;
  // Plain-language summary fields. Rendered as a small read-only form.
  // Keys are snake_case display labels; values are stringified for safety.
  summary?: Record<string, string | number | null | undefined>;
};

/**
 * Ask the host to confirm a destructive action. Returns true on accept,
 * false on decline. Throws `elicitation_unsupported` if the host doesn't
 * implement elicitation — caller should propagate that as a tool error.
 */
export async function confirmDestructive(
  elicit: ElicitFn | undefined,
  req: ConfirmRequest,
): Promise<boolean> {
  if (!elicit) {
    throw new McpToolError(
      "elicitation_unsupported",
      "This tool requires a client that supports MCP elicitation. " +
        "Please upgrade your client, or perform this action in the PayBridgeNP dashboard at https://dashboard.paybridgenp.com.",
      400,
    );
  }

  // Build a form schema that surfaces the summary as read-only display fields
  // plus a single required `confirm` boolean. The host renders this as the
  // confirmation modal.
  const properties: Record<string, unknown> = {};
  const required: string[] = ["confirm"];

  if (req.summary) {
    for (const [k, v] of Object.entries(req.summary)) {
      if (v == null) continue;
      properties[k] = {
        type: typeof v === "number" ? "number" : "string",
        title: humanise(k),
        default: v,
        description: "Read-only — confirms what will happen.",
      };
    }
  }

  properties.confirm = {
    type: "boolean",
    title: "I confirm this action",
    description: "Set to true to proceed.",
  };

  const result = await elicit({
    message: req.message,
    schema: {
      type: "object",
      properties,
      required,
    },
  });

  if (result.action !== "accept") return false;
  return result.content?.confirm === true;
}

function humanise(snake: string): string {
  return snake.replace(/_/g, " ").replace(/^./, (c) => c.toUpperCase());
}
