import type { ToolDefinition } from "../types.js";
import { clampLimit, cursorAndLimitSchema, decodeCursor, idOnlySchema, paginate } from "./_helpers.js";
import { McpToolError } from "../errors.js";
import { confirmDestructive } from "../elicit.js";

type ListResp = { data: unknown[]; meta?: { total?: number; limit?: number; offset?: number } };

const MAX_AMOUNT_PAISA = 10_000_000; // NPR 100,000

export const list_payment_links: ToolDefinition = {
  name: "list_payment_links",
  description:
    "List payment links for the API key's project. Payment links are shareable URLs (no code integration needed) that customers open to pay. Each link has title, amount or amount range, active state, used count, expiry.",
  inputSchema: {
    type: "object",
    properties: {
      cursor: cursorAndLimitSchema.properties.cursor,
      limit: cursorAndLimitSchema.properties.limit,
      active: {
        type: "boolean",
        description: "Filter by active=true (live, accepting payments) or active=false (paused/cancelled).",
      },
    },
    additionalProperties: false,
  },
  annotations: { readOnlyHint: true, title: "List payment links" },
  requiredScopes: ["links:read"],
  async handler(args, ctx) {
    const a = args as { cursor?: string; limit?: number; active?: boolean };
    const limit = clampLimit(a.limit);
    const { offset } = decodeCursor(a.cursor);
    const raw = await ctx.api.get<ListResp>("/v1/payment-links", {
      query: { limit, offset, active: a.active === undefined ? undefined : String(a.active) },
    });
    return paginate(raw, limit, offset);
  },
};

export const get_payment_link: ToolDefinition = {
  name: "get_payment_link",
  description:
    "Fetch a single payment link by id, including its usage stats (views, used_count, conversion_rate).",
  inputSchema: idOnlySchema("link_id", "Payment link id (e.g., lnk_abc123)."),
  annotations: { readOnlyHint: true, title: "Get payment link" },
  requiredScopes: ["links:read"],
  async handler(args, ctx) {
    const { link_id } = args as { link_id: string };
    if (!link_id) throw new Error("link_id is required");
    return ctx.api.get(`/v1/payment-links/${encodeURIComponent(link_id)}`);
  },
};

export const create_payment_link: ToolDefinition = {
  name: "create_payment_link",
  description:
    "Create a new shareable payment link. Provide a fixed `amount` in PAISA (e.g., 250000 = Rs 2,500), or omit `amount` and pass `min_amount`/`max_amount` for an open-amount link the customer fills in. Returns the link id and its public `url` (paste into chat / email / SMS — customer pays via eSewa, Khalti, etc.). Optional fields lock to a single provider, set max uses, expiry, redirect URL, customer pre-fill.",
  inputSchema: {
    type: "object",
    properties: {
      title: {
        type: "string",
        minLength: 1,
        maxLength: 100,
        description: "Short label shown on the hosted page (e.g., 'Course access — December batch').",
      },
      amount: {
        type: "integer",
        minimum: 1,
        maximum: MAX_AMOUNT_PAISA,
        description: "Fixed amount in paisa (1/100 of NPR). Max NPR 100,000 = 10000000 paisa. Omit for open-amount links.",
      },
      min_amount: {
        type: "integer",
        minimum: 100,
        description: "Open-amount lower bound in paisa (only when `amount` is omitted).",
      },
      max_amount: {
        type: "integer",
        maximum: MAX_AMOUNT_PAISA,
        description: "Open-amount upper bound in paisa (only when `amount` is omitted).",
      },
      description: {
        type: "string",
        maxLength: 500,
        description: "Longer description shown on the hosted page.",
      },
      provider: {
        type: "string",
        enum: ["esewa", "khalti", "connectips", "hamropay"],
        description: "Lock to a single provider. Omit to let the customer pick.",
      },
      max_uses: {
        type: "integer",
        minimum: 1,
        maximum: 10000,
        description: "Cap how many times this link can be paid. Omit for unlimited.",
      },
      expires_at: {
        type: "string",
        format: "date-time",
        description: "ISO timestamp when the link stops accepting payments. Max 1 year out.",
      },
      redirect_url: {
        type: "string",
        format: "uri",
        description: "https:// URL the customer is sent to after a successful payment.",
      },
      customer: {
        type: "object",
        description: "Optional pre-fill of the customer fields on the hosted page.",
        properties: {
          name: { type: "string", maxLength: 100 },
          email: { type: "string", format: "email" },
          phone: { type: "string", maxLength: 20 },
        },
        additionalProperties: false,
      },
      reference_id: {
        type: "string",
        maxLength: 100,
        description: "Your own external id (invoice number, etc.). Returned on every webhook tied to this link.",
      },
      metadata: {
        type: "object",
        additionalProperties: true,
        description: "Free-form key/value pairs returned in webhooks + visible in the dashboard.",
      },
    },
    required: ["title"],
    additionalProperties: false,
  },
  annotations: { destructiveHint: true, idempotentHint: false, title: "Create payment link" },
  requiredScopes: ["links:write"],
  async handler(args, ctx) {
    const a = args as {
      title: string;
      amount?: number;
      min_amount?: number;
      max_amount?: number;
      description?: string;
      provider?: "esewa" | "khalti" | "connectips" | "hamropay";
      max_uses?: number;
      expires_at?: string;
      redirect_url?: string;
      customer?: { name?: string; email?: string; phone?: string };
      reference_id?: string;
      metadata?: Record<string, unknown>;
    };

    if (!a.title || a.title.trim().length === 0) {
      throw new McpToolError("invalid_request", "title is required", 400);
    }
    if (a.amount === undefined && a.min_amount === undefined && a.max_amount === undefined) {
      // Allow fully-open link (customer enters any amount within global bounds),
      // but warn loudly. The server will accept this — most callers want a fixed amount.
    }

    return ctx.api.post("/v1/payment-links", {
      body: {
        title: a.title,
        amount: a.amount,
        minAmount: a.min_amount,
        maxAmount: a.max_amount,
        description: a.description,
        provider: a.provider,
        maxUses: a.max_uses,
        expiresAt: a.expires_at,
        redirectUrl: a.redirect_url,
        customerName: a.customer?.name,
        customerEmail: a.customer?.email,
        customerPhone: a.customer?.phone,
        referenceId: a.reference_id,
        metadata: a.metadata,
      },
    });
  },
};

export const update_payment_link: ToolDefinition = {
  name: "update_payment_link",
  description:
    "Update an existing payment link's mutable fields (title, description, active flag, inactive_message, expires_at, max_uses, redirect_url, reference_id). Pass only the fields to change. Pass `null` to clear an optional field.",
  inputSchema: {
    type: "object",
    properties: {
      link_id: { type: "string", description: "Payment link id (lnk_…)." },
      title: { type: "string", maxLength: 100 },
      description: { type: ["string", "null"], maxLength: 500 },
      active: { type: "boolean", description: "Set false to deactivate (auto-sets cancelled_at)." },
      inactive_message: { type: ["string", "null"], maxLength: 300 },
      expires_at: { type: ["string", "null"], format: "date-time" },
      max_uses: { type: ["integer", "null"], minimum: 1 },
      redirect_url: { type: ["string", "null"], format: "uri" },
      reference_id: { type: ["string", "null"], maxLength: 100 },
    },
    required: ["link_id"],
    additionalProperties: false,
  },
  annotations: { destructiveHint: true, idempotentHint: true, title: "Update payment link" },
  requiredScopes: ["links:write"],
  async handler(args, ctx) {
    const a = args as Record<string, unknown> & { link_id: string };
    if (!a.link_id) throw new McpToolError("invalid_request", "link_id is required", 400);
    const { link_id, ...patch } = a;
    return ctx.api.patch(`/v1/payment-links/${encodeURIComponent(link_id)}`, {
      body: {
        // Translate snake_case → camelCase for the apps/api PATCH body.
        title: patch.title,
        description: patch.description,
        active: patch.active,
        inactiveMessage: patch.inactive_message,
        expiresAt: patch.expires_at,
        maxUses: patch.max_uses,
        redirectUrl: patch.redirect_url,
        referenceId: patch.reference_id,
      },
    });
  },
};

export const cancel_payment_link: ToolDefinition = {
  name: "cancel_payment_link",
  description:
    "Soft-deactivate a payment link. The link stays in the dashboard with all its history but stops accepting new payments. Reversible via update_payment_link with active=true. Use this when you want to stop a link in flight; use delete_payment_link to permanently remove a link that has never been used.",
  inputSchema: idOnlySchema("link_id", "Payment link id (lnk_…)."),
  annotations: { destructiveHint: true, idempotentHint: true, title: "Cancel payment link" },
  requiredScopes: ["links:write"],
  async handler(args, ctx) {
    const { link_id } = args as { link_id: string };
    if (!link_id) throw new McpToolError("invalid_request", "link_id is required", 400);
    return ctx.api.post(`/v1/payment-links/${encodeURIComponent(link_id)}/cancel`);
  },
};

export const delete_payment_link: ToolDefinition = {
  name: "delete_payment_link",
  description:
    "Permanently delete a payment link. Only allowed if the link has never been used (used_count = 0). For used links, call cancel_payment_link instead. Always asks for confirmation.",
  inputSchema: idOnlySchema("link_id", "Payment link id (lnk_…)."),
  annotations: { destructiveHint: true, title: "Delete payment link" },
  requiredScopes: ["links:write"],
  async handler(args, ctx) {
    const { link_id } = args as { link_id: string };
    if (!link_id) throw new McpToolError("invalid_request", "link_id is required", 400);

    const ok = await confirmDestructive(ctx.elicit, {
      message: `Permanently delete payment link ${link_id}? This cannot be undone. (Cancel it instead to keep history.)`,
      summary: { link_id, action: "delete (irreversible)" },
    });
    if (!ok) {
      throw new McpToolError("user_cancelled", "Delete cancelled by user.", 0);
    }

    return ctx.api.delete(`/v1/payment-links/${encodeURIComponent(link_id)}`);
  },
};
